import { Router } from 'express';
import { ItemController } from '../controllers/ItemController.js';
import { verificarToken, permitirRoles } from '../middlewares/authMiddleware.js';
const itemRoutes = Router();
const itemController = new ItemController();
itemRoutes.post('/', verificarToken, permitirRoles(['ADMIN', 'SUPERVISOR', 'SUPERVISORA']), itemController.create);
itemRoutes.get('/', verificarToken, permitirRoles(['ADMIN', 'SUPERVISOR', 'SUPERVISORA', 'NUTRICIONISTA']), itemController.list);
itemRoutes.put('/:id', verificarToken, permitirRoles(['ADMIN', 'SUPERVISOR', 'SUPERVISORA']), itemController.update);
itemRoutes.delete('/:id', verificarToken, permitirRoles(['ADMIN', 'SUPERVISOR', 'SUPERVISORA']), itemController.delete);
export { itemRoutes };
